WITH ins_props1 AS (
  INSERT INTO soil_properties (property_name, property_acronym, description, standard_unit, property_level, category_id) 
    SELECT v.property_name, v.property_acronym, v.description, v.standard_unit, v.property_level, c.id
    from (
  values
    ('Acid Saturation', 'Aciexc', NULL, NULL, 1, 'Chemical'),
    ('Aluminium', 'Alu', NULL, NULL, 1, 'Chemical'),
    ('Arsenic', 'As', NULL, NULL, 1, 'Chemical'),
    ('Base Saturation', 'Bas', NULL, NULL, 1, 'Chemical'),
    ('Bulk Density', 'BD', NULL, NULL, 1, 'Physical'),
    ('Boron', 'Bor', NULL, NULL, 1, 'Chemical'),
    ('Cadmium', 'Cad', NULL, NULL, 1, 'Chemical'),
    ('Calcium', 'Cal', NULL, NULL, 1, 'Chemical'),
    ('Carbon/Nitrogen', 'CaN', 'The C/N ratio represents the proportion of carbon to nitrogen in organic matter. It influences decomposition rates and nutrient availability. A lower C/N ratio promotes rapid organic matter breakdown and nitrogen release, while a high ratio may lead to nitrogen immobilization, affecting plant growth. Source: Brady & Weil (2017).', NULL, 1, 'Biological'),
    ('Carbon', 'Car', NULL, NULL, 1, 'Chemical'),
    ('Organic Carbon Index', 'Carorgindx', NULL, NULL, 1, 'Derived'),
    ('Cation Ratios', 'Catratio', NULL, NULL, 1, 'Chemical'),
    ('Calcium Carbonate', 'CC', 'Calcium carbonate', 'g/kg', 1, 'Chemical'),
    ('Cation Exchange Capacity', 'CEC', NULL, NULL, 1, 'Chemical'),
    ('Coarse Fragments', 'CF', NULL, NULL, 1, 'Physical'),
    ('Clay Fraction', 'ClayFractionTexture', 'Clay fraction texture describes the particle-size distribution and properties of the clay fraction within the soil. It influences water retention, aeration, and soil plasticity. Source: Hillel, D. (2004). Introduction to Environmental Soil Physics.', '%w', 1, 'Physical'),
    ('Cobalt', 'Co', NULL, NULL, 1, 'Chemical'),
    ('Copper', 'Cu', NULL, NULL, 1, 'Chemical'),
    ('Drought Vulnerability', 'drghtvul', 'Drought vulnerability refers to the susceptibility of a community, environment, or system to the negative impacts of drought (Li et al., 2015; Serkendiz & Tatli, 2023).', NULL, 1, 'Derived'),
    ('Earthworms', 'earthworm', NULL, NULL, 1, 'Biological'),
    ('Electrical conductivity', 'Eleccond', 'Electrical conductivity (EC) measures the ability of soil to conduct an electrical current, which is directly related to the concentration of soluble salts. It is an essential indicator of soil salinity and is used to assess soil''s suitability for crop growth. High EC levels can reduce plant water uptake and affect germination, while low levels indicate low salinity and better soil health. Source: USDA NRCS.', 'dS/m', 1, 'Chemical'),
    ('Field Capacity', 'FC', NULL, NULL, 1, 'Physical'),
    ('Gypsum', 'gypsum', NULL, NULL, 1, 'Chemical'),
    ('Hydraulic conductivity', 'Hydcond', 'Hydraulic conductivity refers to the rate at which water moves through soil pores under a unit hydraulic gradient. It reflects the soil''s ability to transmit water, influenced by texture, structure, and porosity. Soils with high hydraulic conductivity, like sandy soils, allow rapid water movement, while clayey soils exhibit slower water flow. This property is critical for understanding water infiltration, drainage, and irrigation management. Source: Brady, N.C., & Weil, R.R. (2017). The Nature and Properties of Soils.', 'cm/h', 1, 'Physical'),
    ('Infiltration Rate', 'Infilrate', 'The numeric infiltration rate is the quantitative measurement of the rate at which water infiltrates the soil, typically expressed in millimeters per hour (mm/h). It is a critical factor in soil water management, affecting irrigation practices, runoff, and drainage efficiency. Source: Bouwer, H. (2000). Integrated Water Management for the 21st Century. Water Resources Research.', 'mm/h', 1, 'Physical'),
    ('Iron', 'Iron', NULL, NULL, 1, 'Chemical'),
    ('Soil Erodibility Factor', 'Kwfact', 'Soil erodibility factors (Kw) and (Kf) quantify soil detachment by runoff and raindrop impact. These erodibility factors are indexes used to predict the long-term average soil loss from sheet and rill erosion under crop systems and conservation techniques. Factor Kw applies to the whole soil and is used in the erosion prediction equations USLE and RUSLE. Soil properties that influence rainfall erosion are those that affect:\n Infiltration rate, movement of water through the soil, and water storage capacity.\n Dispersion, detachability, abrasion, and mobility by rainfall and runoff. Some of the most important properties are texture, organic matter content, structure size class, and the saturated hydraulic conductivity of the subsoil.\n Source: U.S. Department of Agriculture, Natural Resources Conservation Service. National soil survey handbook, title 430-VI. Available online. Accessed 9/13/2012.', 't/ha/h', 1, 'Derived'),
    ('Magnesium', 'Mag', NULL, NULL, 1, 'Chemical'),
    ('Manganese', 'Man', NULL, NULL, 1, 'Chemical'),
    ('Mercury', 'Mer', NULL, NULL, 1, 'Chemical'),
    ('Soil Moisture Content', 'moist', 'The Moisture Content Property measures the amount of water present in soil, expressed as a percentage of its dry weight. This property is critical for assessing soil water retention, irrigation needs, and plant-available water. Source: Hillel, D. (2004). Introduction to Environmental Soil Physics.', '%', 1, 'Physical'),
    ('Molybdenum', 'Mol', NULL, NULL, 1, 'Chemical'),
    ('Nematode', 'nematodes', NULL, NULL, 1, 'Biological'),
    ('Nitrogen', 'Nit', NULL, NULL, 1, 'Chemical'),
    ('Depth of Organic Horizon', 'Orghordepth', 'The organic horizon is the uppermost soil layer dominated by organic matter derived from the accumulation and decomposition of plant and animal residues, and it typically forms above the mineral soil or constitutes the entire profile in organic soils. The "O" stands for organic matter. Depth of the organic horizon is the vertical thickness of this organic layer, measured from the soil surface to the boundary with the underlying mineral horizon, and serves as an indicator of organic matter accumulation, biological activity, and surface soil functioning.', 'cm', 1, 'Biological'),
    ('Organic matter', 'Orgmat', 'Soil organic matter is composed of decomposed plant and animal residues, living soil organisms, and humus. It improves soil structure, water retention, nutrient supply, and microbial activity, making it critical for sustainable agriculture and soil health. Source: Brady & Weil (2017).', 'g/kg', 1, 'Biological'),
    ('pH', 'pH', 'Soil pH measures the concentration of hydrogen ions (H⁺) in the soil solution, indicating its acidity or alkalinity on a scale from 1 to 14. Neutral soils have a pH of 7, while values below 7 are acidic and above are alkaline. Soil pH significantly affects nutrient availability, microbial activity, and plant growth. For instance, nutrients like phosphorus are most available in a pH range of 6 to 7. Lime or sulfur applications can adjust soil pH to optimize conditions for crops. Source: USDA Natural Resources Conservation Service (NRCS).', NULL, 1, 'Chemical'),
    ('Phosphorus', 'Pho', NULL, NULL, 1, 'Chemical'),
    ('Phosphorus Retention', 'Phoret', 'Phosphorus retention measures a soil''s capacity to adsorb and hold phosphorus, influenced by soil texture, pH, and mineralogy. While high retention reduces leaching, it may also limit phosphorus availability to plants. Understanding phosphorus retention helps optimize fertilization and minimize environmental impacts. Source: Brady & Weil (2017).', 'mg/kg', 1, 'Derived'),
    ('Porosity', 'Por', 'Porosity refers to the percentage of soil volume occupied by pores or voids, which hold air and water. It directly impacts water infiltration, drainage, and root growth. Soils with high porosity are better suited for crop cultivation, as they provide good aeration and water availability. Source: Brady & Weil (2017).', '%v', 1, 'Physical'),
    ('Potassium', 'Pot', NULL, NULL, 1, 'Chemical'),
    ('Permanent Wilting Point', 'PWP', 'A concentration of liquid water in soil at or below which a plant will wilt and no longer recover its turgidity when placed in a water saturated atmosphere. The type of plant and soil are sources of variation for values of this concentration. The physical definition of the wilting point is conventionally measured as the water content at −1,500 kPa (−15 bar) of suction pressure, or negative hydraulic head.', 'cm³/cm³', 1, 'Physical'),
    ('Depth to Rock Horizon', 'Rhor', 'Depth to the rock horizon is the vertical distance from the soil surface to the R horizon, which consists of unweathered or partially weathered consolidated bedrock. This indicator reflects soil depth limitations affecting rooting depth, water storage capacity, and land use suitability.', 'cm', 1, 'Physical'),
    ('Root Zone', 'Rootzon', 'The root zone is the region of soil influenced by the presence and activity of plant roots. Root zone depth is the vertical extent of this soil region, measured from the soil surface to the maximum effective rooting depth of the vegetation.', 'cm', 1, 'Biological'),
    ('Sand Fraction', 'SandFractionTexture', 'Sand fraction texture describes the proportion of different sand particle sizes (very fine to coarse) within the soil, influencing soil texture and structure. Source: FAO (2006). Guidelines for Soil Description.', '%w', 1, 'Physical'),
    ('Sodium Adsorption Ratio', 'SAR', 'The Sodium Adsorption Ratio (SAR) is an index that expresses the relative proportion of sodium ions (Na⁺) to calcium (Ca²⁺) and magnesium (Mg²⁺) ions in the soil solution or irrigation water. It is calculated from the concentrations of these cations and is used to assess the risk of sodium-induced soil structural degradation. High SAR values indicate a greater likelihood of soil dispersion, reduced infiltration, and impaired soil physical properties.', NULL, 1, 'Derived'),
    ('Silicium', 'Si', NULL, NULL, 1, 'Chemical'),
    ('Silt Fraction', 'SiltFractionTexture', 'Silt fraction texture describes the relative proportion of silt particles in the soil. Silt contributes to soil fertility and moisture retention but is prone to erosion. Source: Brady, N.C., & Weil, R.R. (2008). The Nature and Properties of Soils.', '%w', 1, 'Physical'),
    ('Sodium', 'Sod', NULL, NULL, 1, 'Chemical'),
    ('Sulfur', 'Sul', NULL, NULL, 1, 'Chemical'),
    ('Textural Class', 'TextClass', NULL, NULL, 1, 'Derived'),
    ('Wind Erodibility Index', 'WEI', 'A wind erodibility group (WEG) is a grouping of soils that have similar properties affecting their resistance to soil blowing in cultivated areas. The groups indicate the susceptibility to blowing. The wind erodibility index (I), used in the wind erosion equation, is assigned using the wind erodibility groups.\n\n There is a close correlation between soil blowing and the size and durability of surface clodiness, fragments, organic matter, and the calcareous reaction. The soil properties that are most important with respect to soil blowing are listed below. Soil moisture and the presence of frozen soil also influence soil blowing.\n\n Soil texture class \n Organic matter content \n Carbonates in the fine-earth fraction as determined by effervescence class \n Rock and pararock fragment content \n Mineralogy \n Soils are placed into wind erodibility groups on the basis of the properties of the soil surface layer. Subpart B, Exhibits, Section 618.95 lists the wind erodibility index assigned to the wind erodibility groups. The wind erodibility index values are assigned because the dry soil aggregates are very use-dependent on crop management factors. \n\n Source: U.S. Department of Agriculture, Natural Resources Conservation Service. National soil survey handbook, title 430-VI. Available online. Accessed 2/25/2014.', 't/ha/yr', 1, 'Derived'),
    ('Water Retention', 'WR', NULL, NULL, 1, 'Physical'),
    ('Zinc', 'Zin', NULL, NULL, 1, 'Chemical'),
    ('Available water capacity', 'Avavol', 'Available water capacity (AWC) measures the volume of water soil can retain between field capacity and the permanent wilting point. It represents the water accessible to plants for uptake. High AWC supports better plant growth, while low AWC may necessitate irrigation. Source: USDA NRCS.', 'cm³/cm³', 1, 'Derived'),
    ('Phosphorus Sorption Index', 'PSI', 'PSI is the ratio of phosphorus sorbed by the soil to the logarithm of the equilibrium phosphorus concentration in the solution after a single phosphorus addition.', NULL, 1, 'Chemical')

) AS v(property_name, property_acronym, description, standard_unit, property_level, category_name)
JOIN soil_property_categories c
  using(category_name)
  on conflict(property_name) do update set
updated_at=now()
  RETURNING *
)
INSERT INTO soil_properties (property_name, property_acronym, description, standard_unit, property_level, parent_property_id, category_id) 
    SELECT v.property_name, v.property_acronym, v.description, v.standard_unit, v.property_level, p.id, c.id
    from (
  VALUES
    ('Acid Saturation total', 'Aciexctot', 'Acid saturation represents the amount of hydrogen (H⁺) and aluminium (Al³⁺) ions adsorbed onto soil particles that can be exchanged with the soil solution. It is a key factor in determining soil liming requirements and improving nutrient availability in acidic soils. Source: Brady & Weil (2017).', '%', 2, 'Aciexc', 'Chemical'),
    ('Aluminium Exchangeable', 'Aluexc', 'Aluminium ions bound to exchange surfaces in the soil such as clay minerals and organic matter that can be released to the soil solution upon exchange', 'cmolc/kg', 2, 'Alu', 'Chemical'),
    ('Aluminium Extractable', 'Aluext', 'Aluminium bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)', 'mg/kg', 2, 'Alu', 'Chemical'),
    ('Aluminium Saturation', 'Alusat', 'Measure to describe the relative abundance of aluminium in the soil. It is the percentage of the CEC occupied by aluminium ions (Al³⁺).', '%', 2, 'Aciexc', 'Chemical'),
    ('Aluminium Total', 'Alutot', 'Total concentration of aluminium in the soil, including both soluble and insoluble forms, typically measured after complete digestion of the soil sample.', 'mg/kg', 2, 'Alu', 'Chemical'),
    ('Arsenic Extractable', 'Asext', 'Extractable arsenic refers to the fraction of arsenic in soil that can be considered potentially mobile or bioavailable. This fraction is influenced by soil properties such as pH, redox conditions, iron and aluminium oxides, and organic matter content. Because extractable arsenic better approximates the forms that may leach into groundwater or be taken up by plants, it is commonly used in environmental risk assessment and soil contamination studies to evaluate potential exposure pathways.', 'mg/kg', 2, 'As', 'Chemical'),
    ('Arsenic Total', 'Astot', 'Arsenic is a naturally occurring metalloid found in soils, often originating from geological sources, industrial pollution, or pesticide residues. It exists in various inorganic and organic forms, with some being highly toxic and mobile. Monitoring arsenic levels is essential to assess environmental risks and prevent contamination of water and food sources.', 'mg/kg', 2, 'As', 'Chemical'),
    ('Base saturation - calculated', 'Bascal', 'Base saturation represents the percentage of the soil''s cation exchange capacity (CEC) occupied by basic cations such as calcium (Ca²⁺), magnesium (Mg²⁺), potassium (K⁺), and sodium (Na⁺). Higher base saturation typically correlates with higher fertility and a greater ability to supply essential nutrients to plants. This parameter also influences soil pH buffering capacity. Source: Brady & Weil (2017).', '%', 2, 'Bas', 'Chemical'),
    ('Exchangeable Bases', 'Basexc', 'Exchangeable bases refer to the cations (e.g., calcium, magnesium, potassium, and sodium) adsorbed onto soil colloids, which can readily exchange with soil solution ions. These cations are crucial for maintaining soil fertility, affecting nutrient availability and pH buffering capacity. High exchangeable base levels indicate fertile soil conducive to plant growth. Source: Soil Science Society of America.', 'cmolc/kg', 2, 'Bas', 'Chemical'),
    ('Base saturation - sum of cations', 'Bassum', 'Base saturation calculated as the sum of cations represents the proportion of the cation exchange capacity (CEC) occupied by essential base cations like calcium, magnesium, potassium, and sodium. It provides insight into the soil''s fertility status and its ability to resist acidification. Source: Soil Science Society of America.', '%', 2, 'Bas', 'Chemical'),
    ('Boron Extractable', 'Borext', 'Boron bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)', 'mg/kg', 2, 'Bor', 'Chemical'),
    ('Boron Total', 'BorTot', 'Total boron includes all boron forms in soil, crucial for plant cell wall formation and reproductive processes. Deficiency can impair growth, while toxicity is a risk in arid soils or with excessive irrigation. Source: Havlin et al. (2014).', 'mg/kg', 2, 'Bor', 'Chemical'),
    ('Bulk Density of the fine earth fraction', 'BulDfine', 'This parameter measures the bulk density of the soil fraction smaller than 2 mm (excluding rocks and coarse fragments). It is used to assess the physical properties of soil related to root growth, water movement, and compaction. Source: Soil Science Society of America.', 'g/cm³', 2, 'BD', 'Physical'),
    ('Bulk Density of the whole soil', 'BulDwhole', 'Bulk density measures the mass of soil per unit volume, including both solids and pore spaces. It is a critical parameter for assessing soil compaction, porosity, and water infiltration capacity. High bulk density often indicates poor aeration and root penetration, while low values are associated with high organic matter content and good structure. Source: USDA NRCS.', 'g/cm³', 2, 'BD', 'Physical'),
    ('Cadmium Total', 'Cadtot', 'Cadmium is a heavy metal present in trace amounts in soils, often introduced through industrial pollution or phosphate fertilizers. It is toxic to plants, animals, and humans even at low concentrations. Monitoring cadmium levels is crucial to ensure soil safety and reduce contamination risks in the food chain. Source: Sparks, D.L. (2003).', 'mg/kg', 2, 'Cad', 'Chemical'),
    ('Ca/K ratio', 'CaK', 'The ratio of calcium (Ca²⁺) to potassium (K⁺) in the soil. Influences potassium availability and uptake by plants.', NULL, 2, 'Catratio', 'Chemical'),
    ('Calcium exchangeable', 'Calexc', 'Calcium bound to exchange surfaces in the soil such as clay minerals and organic matter that can be released to the soil solution upon exchange', 'cmolc/kg', 2, 'Cal', 'Chemical'),
    ('Calcium extractable', 'Calext', 'Calcium bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)', 'mg/kg', 2, 'Cal', 'Chemical'),
    ('Calcium soluble', 'Calsol', 'Soluble Calcium cations accumulated in the soil. A contributor to soil salinisation.', 'mg/kg', 2, 'Cal', 'Chemical'),
    ('Calcium total', 'Caltot', 'Total calcium in soil includes all forms, from exchangeable calcium to calcium in minerals. It is essential for plant cell wall structure, enzyme activation, and soil aggregation. Calcium levels influence soil pH and nutrient availability. Source: Havlin et al. (2014).', 'mg/kg', 2, 'Cal', 'Chemical'),
    ('Ca/Mg ratio', 'CaMg', 'The ratio of calcium (Ca²⁺) to magnesium (Mg²⁺) in the soil. This balance affects soil structure, nutrient availability, and plant uptake.', NULL, 2, 'Catratio', 'Chemical'),
    ('Carbon inorganic', 'Carinorg', 'Inorganic carbon in soil primarily consists of carbonates like calcium carbonate and magnesium carbonate. It contributes to soil pH buffering and is a significant feature of arid and calcareous soils. Excess inorganic carbon can immobilize certain nutrients, requiring careful management in agricultural systems. Source: Soil Science Society of America.', 'g/kg', 2, 'Car', 'Chemical'),
    ('Carbon organic', 'Carorg', 'Organic carbon refers to the carbon component of soil organic matter, derived from decomposed plant and microbial residues. It serves as a key energy source for soil microbes and influences nutrient cycling, soil structure, and water retention. Organic carbon is a primary indicator of soil fertility and health. Source: Brady & Weil (2017).', 'g/kg', 2, 'Car', 'Chemical'),
    ('Organic Carbon Density', 'Carorgden', 'Organic carbon density is the amount of organic carbon per unit volume of soil, calculated from soil organic carbon concentration and bulk density. It represents the spatial distribution of organic carbon within the soil profile and is used to compare carbon storage efficiency across soils with different compaction or structure.', 'kg/m³', 2, 'Carorgindx', 'Derived'),
    ('Organic Carbon Stock', 'Carorgstock', 'Organic carbon stock is the total mass of organic carbon stored in a defined soil layer and area, calculated by integrating organic carbon concentration, bulk density, soil depth, and coarse fragment content. It is a key indicator for climate change mitigation, carbon sequestration potential, and soil health assessment.', 't/ha', 2, 'Carorgindx', 'Derived'),
    ('Carbon total', 'Cartot', 'Total carbon in soil includes both organic carbon (from plant and microbial residues) and inorganic carbon (primarily carbonates). It is a fundamental component of soil organic matter, influencing soil fertility, structure, and water retention. High carbon levels are associated with better soil health and productivity. Source: USDA NRCS.', 'g/kg', 2, 'Car', 'Chemical'),
    ('Calcium Saturation', 'Casat', 'Measure describing the relative abundance of calcium in the soil exchange complex. It is the percentage of the cation exchange capacity (CEC) occupied by calcium ions (Ca²⁺).', '%', 2, 'Bas', 'Chemical'),
    ('Cation exchange capacity potential', 'CECpot', 'CEC measures the soil’s ability to hold and exchange positively charged ions (cations). It is a critical indicator of soil fertility, as higher CEC values imply greater capacity to retain essential nutrients like calcium, magnesium, and potassium. Clayey and organic-rich soils typically exhibit higher CEC. Source: Soil Science Society of America.', 'cmolc/kg', 2, 'CEC', 'Chemical'),
    ('Coarse fragments gravimetric', 'cfgr', 'Gravimetric content of coatings and clay accumulation in the form of coarse fragments', '%w', 2, 'CF', 'Physical'),
    ('Coarse fragments volumetric', 'cfvo', 'Volumetric content of coatings and clay accumulation in the form of coarse fragments', '%v', 2, 'CF', 'Physical'),
    ('Copper extractable', 'Copext', 'Copper bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)', 'mg/kg', 2, 'Cu', 'Chemical'),
    ('Copper total', 'Coptot', 'Total copper comprises all soil copper, including bound and free forms. Copper is vital for plant enzyme activation and metabolic processes. Deficiencies can lead to reduced growth and yields, while excess copper may inhibit root development. Source: Soil Science Society of America.', 'mg/kg', 2, 'Cu', 'Chemical'),
    ('Cobalt Total', 'Cotot', 'Cobalt is a trace metal naturally present in soils, primarily derived from parent material and mineral weathering, but it may also be introduced through industrial activities, mining, and the application of fertilizers and amendments. In small amounts, cobalt is an essential micronutrient for some plants and soil microorganisms, but elevated concentrations can be toxic to plants, animals, and humans.', 'mg/kg', 2, 'Co', 'Chemical'),
    ('Cation exchange capacity effective', 'ECEC', 'ECEC is the sum of exchangeable cations in soil at its natural pH. It provides a measure of the soil’s fertility under acidic conditions, as it considers both base cations and exchangeable aluminium. Source: Brady & Weil (2017).', 'cmolc/kg', 2, 'CEC', 'Chemical'),
    ('Gypsum content - weight', 'Gyp', 'The gypsum content, expressed as weight, refers to the soil’s calcium sulfate levels. Gypsum improves soil structure, alleviates sodicity, and enhances water infiltration. It is commonly applied to saline-sodic soils for reclamation. Source: FAO Soil Bulletin.', '%w', 2, 'gypsum', 'Chemical'),
    ('Hydrogen Saturation', 'Hsat', 'Measure describing the relative abundance of hydrogen in the soil exchange complex. It is the percentage of the cation exchange capacity (CEC) occupied by hydrogen ions (H⁺).', '%', 2, 'Aciexc', 'Chemical'),
    ('Iron extractable', 'Iroext', 'Iron bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)', 'mg/kg', 2, 'Iron', 'Chemical'),
    ('Iron total', 'Irotot', 'Total iron includes all iron forms in the soil, from soluble ferrous iron (Fe²⁺) to insoluble ferric iron (Fe³⁺). Iron is essential for plant chlorophyll synthesis and various enzymatic reactions. Deficiency, often seen in alkaline soils, results in chlorosis, while excessive iron can cause toxicity in acidic soils. Source: Soil Chemistry by Bohn et al.', 'mg/kg', 2, 'Iron', 'Chemical'),
    ('Potassium Saturation', 'Potsat', 'Measure describing the relative abundance of potassium in the soil exchange complex. It is the percentage of the cation exchange capacity (CEC) occupied by potassium ions (K⁺).', '%', 2, 'Bas', 'Chemical'),
    ('Saturated Hydraulic Conductivity', 'Ksat', 'Hydraulic conductivity refers to the rate at which water moves through soil pores under a unit hydraulic gradient. It reflects the soil''s ability to transmit water, influenced by texture, structure, and porosity. Soils with high hydraulic conductivity, like sandy soils, allow rapid water movement, while clayey soils exhibit slower water flow. This property is critical for understanding water infiltration, drainage, and irrigation management. Source: Brady, N.C., & Weil, R.R. (2017). The Nature and Properties of Soils. Saturated Hydraulic Conductivity (Ksat) refers to the rate at which water moves through fully saturated soil under a unit hydraulic gradient. It represents the soil’s ability to transmit water when all pores are filled, influenced by factors such as texture, structure, and porosity.', 'cm/h', 2, 'Hydcond', 'Physical'),
    ('Magnesium exchangeable', 'Magexc', 'Magnesium bound to exchange surfaces in the soil such as clay minerals and organic matter that can be released to the soil solution upon exchange', 'cmolc/kg', 2, 'Mag', 'Chemical'),
    ('Magnesium extractable', 'Magext', 'Magnesium bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)', 'mg/kg', 2, 'Mag', 'Chemical'),
    ('Magnesium soluble', 'Magsol', 'Soluble Magnesium cations accumulated in the soil. A contributor to soil salinisation.', 'mg/kg', 2, 'Mag', 'Chemical'),
    ('Manganese exchangeable', 'Manexc', 'Manganese cations adsorbed on soil colloids that are readily exchangeable with the soil solution; indicative of the pool of manganese available for exchange reactions affecting soil chemistry and plant nutrient dynamics.', 'cmolc/kg', 2, 'Man', 'Chemical'),
    ('Manganese extractable', 'Manext', 'Manganese bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)', 'mg/kg', 2, 'Man', 'Chemical'),
    ('Manganese total', 'Mantot', 'Total manganese refers to all forms of manganese in the soil, which is critical for photosynthesis, enzyme activation, and nitrogen metabolism in plants. Manganese deficiencies or toxicities are influenced by soil pH, with deficiencies occurring in high-pH soils and toxicities in low-pH, waterlogged soils. Source: Brady & Weil (2017).', 'mg/kg', 2, 'Man', 'Chemical'),
    ('Mercury total', 'Mertot', 'Mercury is a heavy metal present in soils due to natural sources, industrial emissions, and agricultural inputs like fungicides. It exists in elemental, inorganic, and organic forms, with methylmercury being highly toxic and bioavailable. Monitoring mercury levels is crucial to prevent soil and water contamination and mitigate risks to ecosystems and human health', 'mg/kg', 2, 'Mer', 'Chemical'),
    ('Mg/K ratio', 'MgK', 'The ratio of magnesium (Mg²⁺) to potassium (K⁺) in the soil. Essential for nutrient balance and preventing potassium-induced magnesium deficiency.', NULL, 2, 'Catratio', 'Chemical'),
    ('Magnesium Saturation', 'Mgsat', 'Measure describing the relative abundance of magnesium in the soil exchange complex. It is the percentage of the cation exchange capacity (CEC) occupied by magnesium ions (Mg²⁺).', '%', 2, 'Bas', 'Chemical'),
    ('Magnesium total', 'Mgtot', 'Total magnesium in soil includes exchangeable, soluble, and mineral-bound forms. Magnesium is essential for chlorophyll synthesis, enzyme activation, and nutrient transport in plants. Its availability is influenced by soil pH and texture. Source: Havlin et al. (2014).', 'mg/kg', 2, 'Mag', 'Chemical'),
    ('Molybdenum total', 'Moltot', 'Molybdenum is a micronutrient essential for plant enzymes involved in nitrogen fixation and nitrate reduction. Deficiency, often observed in acidic soils, can lead to stunted growth and poor nitrogen utilization. Its availability increases with higher pH, making liming a common solution for molybdenum deficiencies. Source: Havlin et al. (2014).', 'mg/kg', 2, 'Mol', 'Chemical'),
    ('Nematode Abundance', 'nemabun', 'Elongated, cylindrical, unsegmented worm; includes a number of plant and animal parasites. Nematode abundance is the total number of nematode individuals per unit area of soil, reflecting the size and activity of the soil nematode community and serving as an indicator of soil biological activity and food-web functioning.', 'n. indiv./m²', 2, 'nematodes', 'Biological'),
    ('Nematode Bacterivores species', 'nembact', 'Number of bacterivorous nematodes', 'n/100g', 2, 'nematodes', 'Biological'),
    ('Nematode Biomass', 'nembiom', 'Elongated, cylindrical, unsegmented worm; includes a number of plant and animal parasites. Nematode biomass is the total mass of all nematode individuals per unit area of soil, integrating both abundance and body size, and providing an estimate of their contribution to soil organic matter turnover and ecosystem functioning', 'g/m²', 2, 'nematodes', 'Biological'),
    ('Nematode Fungivores species', 'nemfungi', 'Number of fungivorous nematodes', 'n/100g', 2, 'nematodes', 'Biological'),
    ('Nematode Herbivores species', 'nemherbi', 'Number of herbivorous nematodes', 'n/100g', 2, 'nematodes', 'Biological'),
    ('Nematode Omnivores species', 'nemomni', 'Number of omnivorous nematodes', 'n/100g', 2, 'nematodes', 'Biological'),
    ('Nematode Predators species', 'nempred', 'Number of predatory nematodes', 'n/100g', 2, 'nematodes', 'Biological'),
    ('Nematode Species Richness', 'nemrich', 'Elongated, cylindrical, unsegmented worm; includes a number of plant and animal parasites. Nematode species richness is the number of distinct nematode species (or taxa, depending on taxonomic resolution) present in a soil sample or defined area, and is used as an indicator of soil biodiversity, ecological complexity, and sensitivity to land-use change and disturbance.', 'n. species', 2, 'nematodes', 'Biological'),
    ('Total Number of nematode species', 'nemtot', 'Total number of nematodes', 'n/100g', 2, 'nematodes', 'Biological'),
    ('Nematode Unidentified species', 'nemunidentified', 'Number of unidentified nematodes', 'n/100g', 2, 'nematodes', 'Biological'),
    ('Nitrite soluble', 'Nit2', 'Soluble Nitrite anions accumulated in the soil. A contributor to soil salinisation.', 'mg/kg', 2, 'Nit', 'Chemical'),
    ('Nitrate soluble', 'Nit3', 'Soluble Nitrate anions accumulated in the soil. A contributor to soil salinisation.', 'mg/kg', 2, 'Nit', 'Chemical'),
    ('Nitrogen total', 'Nittot', 'Total nitrogen encompasses all nitrogen forms in soil, including organic nitrogen in humus and inorganic nitrogen such as ammonium (NH₄⁺) and nitrate (NO₃⁻). Nitrogen is essential for plant growth, being a vital component of amino acids, proteins, and chlorophyll. Total nitrogen is a key indicator of soil fertility and its capacity to sustain long-term crop productivity. Source: Brady & Weil (2017).', 'g/kg', 2, 'Nit', 'Chemical'),
    ('Dissolved Phosphorus', 'Phodis', 'Phosphorus present in the soil solution, mainly as inorganic orthophosphate (H₂PO₄⁻ and HPO₄²⁻), representing the immediately mobile and potentially bioavailable phosphorus pool.', 'mg/kg', 2, 'Pho', 'Chemical'),
    ('Phosphorus extractable', 'Phoext', 'Phosphorus bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)', 'mg/kg', 2, 'Pho', 'Chemical'),
    ('Phosphorus total', 'Photot', 'Total phosphorus includes all forms of phosphorus in the soil, both organic and inorganic. While only a fraction is plant-available, total phosphorus serves as a long-term reserve for crop nutrition. Adequate phosphorus levels are crucial for energy transfer, photosynthesis, and root development in plants. Source: Soil Chemistry by Bohn et al.', 'mg/kg', 2, 'Pho', 'Chemical'),
    ('Potassium exchangeable', 'Potexc', 'Potassium bound to exchange surfaces in the soil such as clay minerals and organic matter that can be released to the soil solution upon exchange', 'cmolc/kg', 2, 'Pot', 'Chemical'),
    ('Potassium extractable', 'Potext', 'Potassium bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)', 'mg/kg', 2, 'Pot', 'Chemical'),
    ('Potassium soluble', 'Potsol', 'Soluble Potassium cations accumulated in the soil. A contributor to soil salinisation.', 'mg/kg', 2, 'Pot', 'Chemical'),
    ('Potassium total', 'Pottot', 'Total potassium includes all forms of potassium in soil, such as mineral-bound, exchangeable, and water-soluble potassium. It plays a vital role in plant growth by regulating water balance, enzyme activation, and photosynthesis. While only a fraction of total potassium is readily available to plants, it serves as a reserve to replenish exchangeable potassium over time. Adequate potassium levels improve crop yield, quality, and resistance to stress. Source: Soil Science Society of America.', 'mg/kg', 2, 'Pot', 'Chemical'),
    ('Sodium Saturation', 'Sodexc', 'Exchangeable sodium percentage (ESP) measures the proportion of sodium ions in the cation exchange complex. High ESP levels (>15%) indicate sodic soils, which are prone to poor structure, reduced permeability, and nutrient imbalances. Management strategies include gypsum application and leaching. Source: USDA NRCS.', '%', 2, 'Bas', 'Chemical'),
    ('Sodium exchangeable', 'Sodexp', 'Sodium bound to exchange surfaces in the soil such as clay minerals and organic matter that can be released to the soil solution upon exchange', 'cmolc/kg', 2, 'Sod', 'Chemical'),
    ('Sodium extractable', 'Sodext', 'Sodium bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)', 'mg/kg', 2, 'Sod', 'Chemical'),
    ('Sodium soluble', 'Sodsol', 'Soluble Sodium cations accumulated in the soil. A contributor to soil salinisation.', 'mg/kg', 2, 'Sod', 'Chemical'),
    ('Sodium total', 'Sodtot', 'Total sodium includes all sodium present in soil, both soluble and bound. Excess sodium can lead to sodicity, which disrupts soil structure, reduces permeability, and impairs plant growth. Monitoring sodium levels is crucial for managing soil salinity in arid and irrigated regions. Source: Bohn, H.L., et al. (2001). Soil Chemistry.', 'mg/kg', 2, 'Sod', 'Chemical'),
    ('Sulfur extractable', 'Sulext', 'Sulfur bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)', 'mg/kg', 2, 'Sul', 'Chemical'),
    ('Sulfur total', 'Sultot', 'Total sulfur in soil includes both organic and inorganic forms, such as sulfates and sulfur in organic matter. Sulfur is essential for protein synthesis and enzyme functions in plants. Deficiency leads to stunted growth and yellowing of leaves. Total sulfur provides insight into the soil''s potential to release plant-available sulfur over time, critical for sustaining crop health. Source: Havlin, J.L., et al. (2014). Soil Fertility and Fertilizers.', 'mg/kg', 2, 'Sul', 'Chemical'),
    ('USDA Texture', 'usda_texture', 'USDA textural class is a soil classification based on the relative proportions of sand, silt, and clay in the fine earth fraction. It assigns soils to standardized texture classes according to the USDA soil texture triangle and is used to characterise soil physical behaviour, including water retention, aeration, and workability. The textural classes are encoded as follows: 1 = Clay, 2 = Silty Clay, 3 = Sandy Clay, 4 = Clay Loam, 5 = Silty Clay Loam, 6 = Sandy Clay Loam, 7 = Loam, 8 = Silty Loam, 9 = Sandy Loam, 10 = Silt, 11 = Loamy Sand, 12 = Sand', NULL, 2, 'TextClass', 'Derived'),
    ('Earthworms Abundance', 'wormabun', 'Earthworms are segmented invertebrates that play a key role in soil structure formation, organic matter decomposition, and nutrient cycling through their feeding and burrowing activities. Earthworms abundance is the total number of individual earthworms present per unit area of soil, and serves as an indicator of soil biological activity, organic matter availability, and overall soil health.', 'n. indiv./m²', 2, 'earthworm', 'Biological'),
    ('Earthworms Biomass', 'wormbiom', 'Earthworms are segmented invertebrates that strongly influence soil physical structure and biogeochemical processes. Earthworms biomass is the total mass of all earthworm individuals per unit area of soil, integrating both abundance and body size, and reflecting their contribution to soil aggregation, aeration, and nutrient cycling.', 'g/m²', 2, 'earthworm', 'Biological'),
    ('Earthworms Species Richness', 'wormrich', 'Earthworms are segmented invertebrates comprising multiple ecological groups with distinct functional roles in soil ecosystems. Earthworms species richness is the number of distinct earthworm species present in a defined area or soil sample, and is used as an indicator of soil biodiversity, ecological complexity, and resilience to land-use change and disturbance.', 'n. species', 2, 'earthworm', 'Biological'),
    ('Water Retention Gravimetric', 'WRG', 'Gravimetric water retention refers to the amount of water held by the soil measured by weight, often expressed in terms of mass per unit mass of soil. It is a fundamental method for assessing soil moisture content and can be determined at various suction pressures like 33 kPa or 1500 kPa. Source: Soil Science Society of America.', '%w', 2, 'WR', 'Physical'),
    ('Water Retention Volumetric', 'WRV', 'Volumetric water retention refers to the amount of water retained in the soil, expressed as a volume per unit volume of soil. This measure is crucial for understanding the soil''s ability to retain and supply water to plants, and it is often assessed at different matric potentials, such as 33 kPa or 1500 kPa, depending on the context. Source: Soil Science Society of America', '%v', 2, 'WR', 'Physical'),
    ('Zinc extractable', 'Zinext', 'Zinc bound to the soil matrix but that can be released into the soil solution (i.e. become bio-available)', 'mg/kg', 2, 'Zin', 'Chemical'),
    ('Zinc total', 'zintotal', 'Zinc is a micronutrient essential for plant enzyme systems, protein synthesis, and growth regulation. Deficiency is common in calcareous soils and results in stunted growth and chlorosis. Zinc fertilizers or soil pH adjustments can address deficiencies. Source: Havlin et al. (2014).', 'mg/kg', 2, 'Zin', 'Chemical')
) AS v(property_name, property_acronym, description, standard_unit, property_level, parent_property_acronym
, category_name)
JOIN soil_property_categories c
  using(category_name)
 JOIN ins_props1 p
	on p.property_acronym=v.parent_property_acronym
on conflict(property_name) do nothing;